// 三载体一致:纯 JS、无 DOM/uplink/shadow 足迹
import currency from 'https://cdn.jsdelivr.net/npm/currency.js@2/+esm';
let money = currency(data.amount, data.options ?? {});
const methods = { plus:'add', minus:'subtract', times:'multiply', divide:'divide' };
for (const step of data.operations ?? []) money = money[methods[step.op]](step.operand);
const parts = data.split_count === undefined ? undefined : money.distribute(data.split_count).map(x => x.format());
const result = { value: money.value, intValue: money.intValue, formatted: money.format(), parts };
